import React, { useState, useEffect } from "react";
import {
  Container,
  Accordion,
  Row,
  Col,
  ProgressBar,
  Table,
  Spinner,
  Alert,
} from "react-bootstrap";
import "bootstrap/dist/css/bootstrap.min.css";

export default function TimeTable() {
  const [resultsData, setResultsData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch("http://localhost:65000/api/students/getstudentresults", {
      method: "GET",
      credentials: "include", // important for session cookies
    })
      .then(async (res) => {
        if (!res.ok) {
          const msg = await res.text();
          throw new Error(msg || "Failed to fetch results");
        }
        return res.json();
      })
      .then((data) => {
        setResultsData(data);
        setLoading(false);
      })
      .catch((err) => {
        setError(err.message);
        setLoading(false);
      });
  }, []);

  const getProgressVariant = (percentage) => {
    if (percentage >= 85) return "success";
    if (percentage >= 50) return "warning";
    return "danger";
  };

  if (loading)
    return (
      <Container className="text-center my-5">
        <Spinner animation="border" />
        <p>Loading results...</p>
      </Container>
    );

  if (error)
    return (
      <Container className="my-5">
        <Alert variant="danger">{error}</Alert>
      </Container>
    );

  const allKeys = resultsData.courses?.map((_, idx) => idx.toString()) || [];

  return (
    <Container className="my-4">
      <h2 className="mb-4 text-center" style={{ color: "#2c3e50" }}>
        Results - Semester {resultsData.currentSemester}
      </h2>

      <Accordion defaultActiveKey={allKeys} alwaysOpen>
        {resultsData.courses?.map((course, index) => (
          <Accordion.Item eventKey={index.toString()} key={course.courseCode}>
            <Accordion.Header>
              <Row className="w-100 align-items-center">
                <Col xs={12} md={6}>
                  <strong>{course.courseCode}</strong> - {course.courseName}
                </Col>
                <Col xs={12} md={6} className="mt-2 mt-md-0">
                  <ProgressBar
                    now={course.percentage}
                    label={`${course.percentage}%`}
                    variant={getProgressVariant(course.percentage)}
                  />
                </Col>
              </Row>
            </Accordion.Header>

            <Accordion.Body>
              <Row className="mb-3">
                <Col xs={6}>
                  <strong>Status:</strong> {course.status}
                </Col>
                <Col xs={6}>
                  <strong>Grade:</strong>{" "}
                  <span
                    style={{
                      color:
                        course.grade === "A"
                          ? "green"
                          : course.grade === "B"
                          ? "orange"
                          : "red",
                      fontWeight: "bold",
                    }}
                  >
                    {course.grade}
                  </span>{" "}
                  ({course.gradePoints} pts)
                </Col>
                <Col xs={6}>
                  <strong>Marks:</strong> {course.obtainedMarks} /{" "}
                  {course.totalMarks}
                </Col>
                <Col xs={6}>
                  <strong>Section:</strong> {course.sectionName} | Batch:{" "}
                  {course.batchName}
                </Col>
              </Row>

              {course.assessments.length === 0 ? (
                <p>No assessments available.</p>
              ) : (
                <div className="table-responsive">
                  <Table striped bordered hover>
                    <thead className="table-dark">
                      <tr>
                        <th>Assessment</th>
                        <th>Obtained Marks</th>
                        <th>Total Marks</th>
                        <th>Weightage (%)</th>
                        <th>Progress</th>
                      </tr>
                    </thead>
                    <tbody>
                      {course.assessments.map((a, idx) => (
                        <tr key={idx}>
                          <td>{a.name}</td>
                          <td>{a.obtainedMarks}</td>
                          <td>{a.totalMarks}</td>
                          <td>{a.weightage}</td>
                          <td>
                            <ProgressBar
                              now={(a.obtainedMarks / a.totalMarks) * 100}
                              variant={getProgressVariant(
                                (a.obtainedMarks / a.totalMarks) * 100
                              )}
                              label={`${(
                                (a.obtainedMarks / a.totalMarks) *
                                100
                              ).toFixed(0)}%`}
                            />
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </Table>
                </div>
              )}
            </Accordion.Body>
          </Accordion.Item>
        ))}
      </Accordion>
    </Container>
  );
}
